import java.util.*;

public class Solution {
    public static long solve(long[][] edges, boolean[] online, long k) {
        int n = online.length;
        List<List<int[]>> adj = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int cost = (int) edge[2];
            adj.get(u).add(new int[]{v, cost});
        }

        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> {
            if (a[0] != b[0]) {
                return Long.compare(-a[0], -b[0]);
            }
            return Long.compare(a[1], b[1]);
        });

        long[] best_min = new long[n];
        Arrays.fill(best_min, -Long.MAX_VALUE);

        pq.offer(new long[]{-Long.MAX_VALUE, 0, 0});

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long current_min_edge = -current[0];
            long total_cost = current[1];
            int node = current[2];

            if (node == n - 1) {
                return current_min_edge;
            }

            if (current_min_edge < best_min[node]) {
                continue;
            }

            for (int[] edge : adj.get(node)) {
                int v = edge[0];
                int cost = edge[1];

                if (!online[v]) {
                    continue;
                }

                long new_min_edge = Math.min(current_min_edge, cost);
                long new_total_cost = total_cost + cost;

                if (new_total_cost > k) {
                    continue;
                }

                if (new_min_edge > best_min[v]) {
                    best_min[v] = new_min_edge;
                    pq.offer(new long[]{-new_min_edge, new_total_cost, v});
                }
            }
        }

        return -1;
    }
}
