import java.util.*;

public class Solution {
    public static long solve(long[][] edges, boolean[] online, long k) {
        int n = online.length;
        List<List<int[]>> adj = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long cost = edge[2];
            adj.get(u).add(new int[]{v, (int) cost});
        }

        long[] bestMin = new long[n];
        Arrays.fill(bestMin, Long.MIN_VALUE);
        bestMin[0] = Long.MAX_VALUE;

        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(b[0], a[0]));

        pq.offer(new long[]{Long.MAX_VALUE, 0, 0});

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long currentMin = current[0];
            long totalCost = current[1];
            int u = current[2];

            if (u == n - 1) {
                return currentMin;
            }

            if (currentMin < bestMin[u]) {
                continue;
            }

            for (int[] edge : adj.get(u)) {
                int v = edge[0];
                long cost = edge[1];

                if (!online[v]) {
                    continue;
                }

                long newMin = Math.min(currentMin, cost);
                long newTotal = totalCost + cost;

                if (newTotal > k) {
                    continue;
                }

                if (newMin > bestMin[v]) {
                    bestMin[v] = newMin;
                    pq.offer(new long[]{newMin, newTotal, v});
                }
            }
        }

        return -1;
    }
}
